import{_ as e,c as d,d as a,o as r}from"./app-BN7yO2ds.js";const s={};function n(o,t){return r(),d("div",null,[...t[0]||(t[0]=[a('<h2 id="前言" tabindex="-1"><a class="header-anchor" href="#前言"><span>前言</span></a></h2><p>在信息爆炸的时代，社交媒体的时间线往往被算法控制，你看到的内容取决于平台想让你看到什么。<strong>feeeed</strong>（四连 e）是一款专注于让你掌控自己信息源的 iOS 应用——构建属于你自己的、无广告的、个性化的资讯聚合阅读器。</p><blockquote><p>&quot;Stay informed without losing sanity. A feed curated by you, not the social-media mob.&quot;</p></blockquote><h2 id="应用简介" tabindex="-1"><a class="header-anchor" href="#应用简介"><span>应用简介</span></a></h2><p><strong>feeeed</strong> 由独立开发者 Nate Parrott 开发，是一款免费的 iOS/iPadOS 阅读器应用（macOS via compatibility mode）。它不仅仅是一个 RSS 阅读器，而是将多种内容源统一到一个流畅的时间线中。</p><h3 id="核心特点" tabindex="-1"><a class="header-anchor" href="#核心特点"><span>核心特点</span></a></h3><table><thead><tr><th>特性</th><th>说明</th></tr></thead><tbody><tr><td><strong>隐私优先</strong></td><td>100% 本地运行，无服务器、无账户、不收集数据</td></tr><tr><td><strong>多源订阅</strong></td><td>RSS、YouTube、Reddit、Hacker News、Mastodon、Threads、TikTok 等</td></tr><tr><td><strong>AI 摘要</strong></td><td>免费文章 AI 智能摘要</td></tr><tr><td><strong>阅读模式</strong></td><td>快速、专注、可自定义的阅读器模式</td></tr><tr><td><strong>离线支持</strong></td><td>下载文章离线阅读</td></tr><tr><td><strong>小组件</strong></td><td>iOS 主屏幕小组件</td></tr><tr><td><strong>自定义提醒</strong></td><td>每日步数目标、健康数据、照片回忆等</td></tr></tbody></table><h3 id="支持的平台" tabindex="-1"><a class="header-anchor" href="#支持的平台"><span>支持的平台</span></a></h3><ul><li>iPhone (iOS 16.0+)</li><li>iPad (iPadOS 16.0+)</li><li>Mac (macOS 13.0+, Apple M1+)</li><li>Apple Vision (visionOS 1.0+)</li></ul><h2 id="功能亮点" tabindex="-1"><a class="header-anchor" href="#功能亮点"><span>功能亮点</span></a></h2><h3 id="_1-订阅任意网站" tabindex="-1"><a class="header-anchor" href="#_1-订阅任意网站"><span>1. 订阅任意网站</span></a></h3><p>通过 RSS 订阅任何网站的内容，也可以直接从 Safari 分享菜单添加网站关注（v17+ 新功能）。</p><h3 id="_2-多平台内容聚合" tabindex="-1"><a class="header-anchor" href="#_2-多平台内容聚合"><span>2. 多平台内容聚合</span></a></h3><p>除了传统 RSS，feeeed 还支持：</p><ul><li><strong>YouTube 频道</strong> - 订阅你喜欢的频道</li><li><strong>Subreddits</strong> - 关注 Reddit 社区</li><li><strong>Hacker News</strong> - 获取技术新闻</li><li><strong>Mastodon/Threads</strong> - 关注社交动态</li><li><strong>Newsletter</strong> - Gmail 邮件 newsletter（已暂停，Google 停用了相关 API）</li></ul><h3 id="_3-个性化卡片" tabindex="-1"><a class="header-anchor" href="#_3-个性化卡片"><span>3. 个性化卡片</span></a></h3><p>feeeed 可以将任何网站的一部分转换为实时卡片，方便追踪特定内容区域。</p><h3 id="_4-健康与生活集成" tabindex="-1"><a class="header-anchor" href="#_4-健康与生活集成"><span>4. 健康与生活集成</span></a></h3><ul><li><strong>步数统计</strong> - 追踪每日步数和 10,000 步目标进度</li><li><strong>照片回忆</strong> - 偶尔展示旧照片</li><li><strong>生日提醒</strong> - 联系人生日提醒</li><li><strong>自定义提醒</strong> - 创建个性化提醒卡片</li></ul><h3 id="_5-ai-机器人" tabindex="-1"><a class="header-anchor" href="#_5-ai-机器人"><span>5. AI 机器人</span></a></h3><p>内置 AI 助手可以根据主题推荐订阅源，例如询问&quot;有哪些关于足球的博客或 newsletter&quot;，机器人会给出建议。</p><h2 id="推荐-rss-订阅源" tabindex="-1"><a class="header-anchor" href="#推荐-rss-订阅源"><span>推荐 RSS 订阅源</span></a></h2><h3 id="ai-与科技资讯" tabindex="-1"><a class="header-anchor" href="#ai-与科技资讯"><span>AI 与科技资讯</span></a></h3><table><thead><tr><th>订阅源</th><th>地址</th><th>说明</th></tr></thead><tbody><tr><td><strong>AI HOT 精选</strong></td><td><code>https://aihot.virxact.com/feed.xml</code></td><td>每日 AI 行业动态、模型发布、产品发布、行业事件</td></tr><tr><td><strong>AI HOT 全量</strong></td><td><code>https://aihot.virxact.com/feed/all.xml</code></td><td>AI HOT 全量资讯聚合</td></tr></tbody></table><h3 id="技术博客" tabindex="-1"><a class="header-anchor" href="#技术博客"><span>技术博客</span></a></h3><table><thead><tr><th>订阅源</th><th>地址</th><th>说明</th></tr></thead><tbody><tr><td><strong>Hacker News</strong></td><td><code>https://hnrss.org/frontpage</code></td><td>技术社区热门话题</td></tr><tr><td><strong>TechCrunch</strong></td><td>RSS</td><td>科技行业新闻</td></tr><tr><td><strong>Ars Technica</strong></td><td>RSS</td><td>深度技术报道</td></tr></tbody></table><h3 id="ai-研究与模型" tabindex="-1"><a class="header-anchor" href="#ai-研究与模型"><span>AI 研究与模型</span></a></h3><table><thead><tr><th>订阅源</th><th>地址</th><th>说明</th></tr></thead><tbody><tr><td><strong>Hugging Face Blog</strong></td><td><code>https://huggingface.co/blog/feed.xml</code></td><td>开源模型与 AI 研究</td></tr><tr><td><strong>OpenAI Blog</strong></td><td><code>https://openai.com/blog/rss.xml</code></td><td>OpenAI 最新研究</td></tr><tr><td><strong>Anthropic Research</strong></td><td><code>https://www.anthropic.com/research/rss.xml</code></td><td>Claude 相关研究</td></tr></tbody></table><h3 id="中文资讯" tabindex="-1"><a class="header-anchor" href="#中文资讯"><span>中文资讯</span></a></h3><table><thead><tr><th>订阅源</th><th>地址</th><th>说明</th></tr></thead><tbody><tr><td><strong>IT之家</strong></td><td>RSS</td><td>科技资讯</td></tr><tr><td><strong>微信公众号精选</strong></td><td>RSS</td><td>中文优质内容</td></tr></tbody></table><h2 id="使用技巧" tabindex="-1"><a class="header-anchor" href="#使用技巧"><span>使用技巧</span></a></h2><h3 id="_1-从-safari-添加订阅" tabindex="-1"><a class="header-anchor" href="#_1-从-safari-添加订阅"><span>1. 从 Safari 添加订阅</span></a></h3><ol><li>在 Safari 中打开目标网站</li><li>点击分享按钮</li><li>选择 <strong>feeeed</strong></li><li>点击 <strong>Follow</strong> 关注</li></ol><h3 id="_2-导入-opml" tabindex="-1"><a class="header-anchor" href="#_2-导入-opml"><span>2. 导入 OPML</span></a></h3><p>如果你是其他 RSS 阅读器的用户，可以导出 OPML 文件并在 feeeed 中导入，快速迁移订阅源。</p><h3 id="_3-调整信息流算法" tabindex="-1"><a class="header-anchor" href="#_3-调整信息流算法"><span>3. 调整信息流算法</span></a></h3><ul><li><strong>Best Variety</strong> (默认) - 算法推荐，平衡内容多样性</li><li><strong>Chronological</strong> - 完全按时间顺序</li><li>可以在底部标签栏固定 <strong>Latest</strong> 快速切换</li></ul><h3 id="_4-离线阅读" tabindex="-1"><a class="header-anchor" href="#_4-离线阅读"><span>4. 离线阅读</span></a></h3><p>在有网络时下载数十篇文章，无网时随时阅读，适合通勤或旅行。</p><h2 id="与其他阅读器对比" tabindex="-1"><a class="header-anchor" href="#与其他阅读器对比"><span>与其他阅读器对比</span></a></h2><table><thead><tr><th>特性</th><th>feeeed</th><th>Reeder</th><th>Feedbin</th><th>NetNewsWire</th></tr></thead><tbody><tr><td>多平台支持</td><td>✅</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Reddit/HN 集成</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>健康数据集成</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>100% 本地隐私</td><td>✅</td><td>✅</td><td>❌</td><td>✅</td></tr><tr><td>免费</td><td>✅</td><td>付费</td><td>付费</td><td>免费</td></tr><tr><td>AI 摘要</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr></tbody></table><h2 id="下载与链接" tabindex="-1"><a class="header-anchor" href="#下载与链接"><span>下载与链接</span></a></h2><table><thead><tr><th>资源</th><th>链接</th></tr></thead><tbody><tr><td>App Store</td><td><a href="https://apps.apple.com/us/app/feeeed-rss-reader-and-more/id1600187490" target="_blank" rel="noopener noreferrer">feeeed: RSS Reader and More</a></td></tr><tr><td>官方网站</td><td><a href="https://feeeed.nateparrott.com/" target="_blank" rel="noopener noreferrer">feeeed.nateparrott.com</a></td></tr></tbody></table><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结"><span>总结</span></a></h2><p>feeeed 最大的特点是<strong>打破信息孤岛</strong>——不再需要打开多个 App 刷不同平台，在一个应用中即可获取所有你关心的内容。其隐私优先的设计理念和丰富的个性化功能，使其成为追求信息自主用户的理想选择。</p><p>如果你受够了社交媒体的信息茧房，想要真正掌控自己的信息流，feeeed 值得一试。</p>',46)])])}const i=e(s,[["render",n]]),l=JSON.parse('{"path":"/blog/feeeed-rss-reader/","title":"feeeed - iOS RSS 阅读器与个人资讯聚合 | Blog","lang":"zh-CN","frontmatter":{"title":"feeeed - iOS RSS 阅读器与个人资讯聚合","tags":["iOS","RSS","效率工具"],"createTime":"2026/06/19 00:00:00","updateTime":"2026/06/19 00:00:00","permalink":"/blog/feeeed-rss-reader/"},"readingTime":{"minutes":3.67,"words":1100},"git":{"createdTime":1781842825000,"updatedTime":1781842825000,"contributors":[{"name":"LiuKun","username":"LiuKun","email":"liukunup@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/LiuKun?v=4","url":"https://github.com/LiuKun"}]},"filePathRelative":"blog/feeeed-rss-reader.md","headers":[],"categoryList":[]}');export{i as comp,l as data};
